import{_ as A,C as p,o,c as C,j as r,a,b as l,w as t,E as i,a4 as s,a5 as E}from"./chunks/framework.sOZL8giL.js";const P=JSON.parse('{"title":"工具与协议","description":"","frontmatter":{},"headers":[],"relativePath":"03-Agent基础/02-工具与协议.md","filePath":"03-Agent基础/02-工具与协议.md","lastUpdated":null}'),u={name:"03-Agent基础/02-工具与协议.md"};function d(B,e,g,c,m,h){const n=p("Mermaid");return o(),C("div",null,[e[2]||(e[2]=r("h1",{id:"工具与协议",tabindex:"-1"},[a("工具与协议 "),r("a",{class:"header-anchor",href:"#工具与协议","aria-label":'Permalink to "工具与协议"'},"​")],-1)),e[3]||(e[3]=r("blockquote",null,[r("p",null,[a("本章是 "),r("strong",null,"Hermes Engineering 系列"),a("第 3 模块的第 2 章。")])],-1)),e[4]||(e[4]=r("p",null,'工具让 LLM 从"会说"变成"能做"。MCP 协议让工具像 USB 设备一样即插即用。',-1)),e[5]||(e[5]=r("hr",null,null,-1)),e[6]||(e[6]=r("h2",{id:"function-calling-让-llm-学会请求帮助",tabindex:"-1"},[a("Function Calling：让 LLM 学会请求帮助 "),r("a",{class:"header-anchor",href:"#function-calling-让-llm-学会请求帮助","aria-label":'Permalink to "Function Calling：让 LLM 学会请求帮助"'},"​")],-1)),(o(),l(s,null,{default:t(()=>[i(n,{id:"mermaid-15",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20User%20as%20%E7%94%A8%E6%88%B7%0A%20%20%20%20participant%20LLM%20as%20LLM%0A%20%20%20%20participant%20Program%20as%20%E7%A8%8B%E5%BA%8F%0A%20%20%20%20participant%20Tool%20as%20%E5%A4%96%E9%83%A8%E5%B7%A5%E5%85%B7%0A%0A%20%20%20%20User-%3E%3ELLM%3A%20%E4%BB%8A%E5%A4%A9%E5%8C%97%E4%BA%AC%E5%A4%A9%E6%B0%94%E6%80%8E%E4%B9%88%E6%A0%B7%EF%BC%9F%0A%20%20%20%20LLM-%3E%3EProgram%3A%20%E8%BE%93%E5%87%BA%20JSON%3A%20%7Btool%3A%20%22get_weather%22%2C%20params%3A%20%7Bcity%3A%20%22%E5%8C%97%E4%BA%AC%22%7D%7D%0A%20%20%20%20Program-%3E%3ETool%3A%20%E8%B0%83%E7%94%A8%E5%A4%A9%E6%B0%94%20API%0A%20%20%20%20Tool-%3E%3EProgram%3A%20%E8%BF%94%E5%9B%9E%3A%20%E6%99%B4%2025%C2%B0C%0A%20%20%20%20Program-%3E%3ELLM%3A%20%E6%8A%8A%E7%BB%93%E6%9E%9C%E5%96%82%E5%9B%9E%0A%20%20%20%20LLM-%3E%3EUser%3A%20%E5%8C%97%E4%BA%AC%E4%BB%8A%E5%A4%A9%E6%99%B4%EF%BC%8C25%C2%B0C%0A%20%20%20%20Note%20over%20LLM%3A%20LLM%20%E4%B8%8D%E7%9B%B4%E6%8E%A5%E5%9B%9E%E7%AD%94%3Cbr%2F%3E%E8%80%8C%E6%98%AF%E8%BE%93%E5%87%BA%E5%B7%A5%E5%85%B7%E8%B0%83%E7%94%A8%E8%AF%B7%E6%B1%82%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[a(" Loading... ",-1)])]),_:1})),e[7]||(e[7]=E('<blockquote><p>💡 <strong>图解：</strong> Function Calling 让 LLM 从&quot;编答案&quot;变成&quot;说需求&quot;——它不查天气，但它知道该调谁来查。</p></blockquote><p>LLM 有一个致命缺陷：它只能编，不能查。你问今天北京天气怎么样，它会根据训练数据编一个答案。知识截止到训练时间，不知道今天的天气、利率、新闻。</p><p>Function Calling 的本质：让 LLM 不直接回答问题，而是输出一个 JSON 说&quot;我需要调用某个工具&quot;。程序解析 JSON 后真正调用工具，把结果喂回给 LLM。</p><p>LLM 是根据 description 来理解怎么填参数的。description 越清晰，LLM 填得越准。检验方法：把 description 给不懂技术的人看，如果他说不知道，那 LLM 大概率也不知道。</p><hr><h2 id="工具定义的三部分" tabindex="-1">工具定义的三部分 <a class="header-anchor" href="#工具定义的三部分" aria-label="Permalink to &quot;工具定义的三部分&quot;">​</a></h2><p><strong>元数据</strong>——工具是干什么的（name、description、category）。生产必备字段：timeout_seconds（防工具卡死）、rate_limit（防疯狂调用）、dangerous（危险操作需确认）、cost_per_use（追踪成本）、sandboxed（防恶意代码逃逸）。</p><p><strong>参数定义</strong>——需要什么输入（name、type、description、required）。LLM 是根据 description 来理解怎么填参数的，这是最重要的字段。</p><p><strong>执行逻辑</strong>——具体干什么。关键：异步不阻塞、安全不直接 eval、结构化返回 ToolResult（含 success 和 error 字段）。</p><h3 id="容错处理" tabindex="-1">容错处理 <a class="header-anchor" href="#容错处理" aria-label="Permalink to &quot;容错处理&quot;">​</a></h3><p>LLM 填参数不准怎么办？类型强转——整数接受浮点数和数字字符串，布尔接受常见字符串形式。参数有 min/max 时自动 clamp。</p><hr><h2 id="工具管理" tabindex="-1">工具管理 <a class="header-anchor" href="#工具管理" aria-label="Permalink to &quot;工具管理&quot;">​</a></h2><p>工具太多 LLM 会懵。测试显示 20 个工具时选择准确率明显下降，5 个相关工具时高得多。要根据任务类型只暴露相关工具——研究任务给搜索和读取，数据分析给计算和数据库，代码任务给文件操作。</p><p>限流两层：工具级别限流（每次调用前检查）+ 滑动窗口限流（基于时间间隔）。</p><hr><h2 id="mcp-协议-工具的-usb-接口" tabindex="-1">MCP 协议：工具的 USB 接口 <a class="header-anchor" href="#mcp-协议-工具的-usb-接口" aria-label="Permalink to &quot;MCP 协议：工具的 USB 接口&quot;">​</a></h2><p>2025 年 MCP 已经成为 Agent 工具集成的事实标准——9700 万月下载、1 万+活跃 Server，加入 Linux Foundation 做中立治理。</p><p>没有 MCP 之前：每个 Agent 都要重新实现 GitHub 集成，格式不统一（GitHub 返回 issues、Jira 返回 tickets），权限分散，难以复用。</p><p>MCP 统一了接口：所有工具用相同 JSON-RPC 格式通信，新工具只需实现 MCP Server 所有 Client 自动支持，社区写好的 Server 任何 Agent 都能用，认证授权在 Server 端统一管理。</p>',20)),(o(),l(s,null,{default:t(()=>[i(n,{id:"mermaid-72",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5BCursor%5D%20--%3E%7CMCP%20Client%7C%20E%5BMCP%20%E7%BB%9F%E4%B8%80%E6%8E%A5%E5%8F%A3%3Cbr%2F%3EJSON-RPC%5D%0A%20%20%20%20B%5BChatGPT%5D%20--%3E%7CMCP%20Client%7C%20E%0A%20%20%20%20C%5BWindsurf%5D%20--%3E%7CMCP%20Client%7C%20E%0A%20%20%20%20E%20--%3E%7CMCP%20Server%7C%20D1%5BGitHub%5D%0A%20%20%20%20E%20--%3E%7CMCP%20Server%7C%20D2%5BJira%5D%0A%20%20%20%20E%20--%3E%7CMCP%20Server%7C%20D3%5BSlack%5D%0A%20%20%20%20E%20--%3E%7CMCP%20Server%7C%20D4%5B%E8%87%AA%E5%AE%9A%E4%B9%89%E5%B7%A5%E5%85%B7%5D%0A%20%20%20%20style%20E%20fill%3A%234a9%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[a(" Loading... ",-1)])]),_:1})),e[8]||(e[8]=E('<blockquote><p>💡 <strong>图解：</strong> MCP 就是 Agent 工具世界的 USB 接口——一个 Server 写好，所有 Client 都能用。</p></blockquote><h3 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h3><p><strong>Client 和 Server</strong>：Client 调用工具使用资源（Cursor、Windsurf、ChatGPT），Server 提供工具暴露资源。</p><p><strong>Tools vs Resources</strong>：Tools 是执行操作改变状态的（写操作），Resources 是读取数据不改变状态的（读操作），还支持订阅变更通知。</p><h3 id="安全问题" tabindex="-1">安全问题 <a class="header-anchor" href="#安全问题" aria-label="Permalink to &quot;安全问题&quot;">​</a></h3><p><strong>Prompt Injection</strong>：恶意 Server 在返回值里注入指令，LLM 可能把工具输出当成系统指令执行。缓解：严格过滤、明确标记隔离工具输出。</p><p><strong>Tool 权限组合攻击</strong>：单独看每个工具安全，但组合起来 Agent 可能用 read_file 读 SSH 密钥再用 http_request 发到攻击者服务器。缓解：最小权限原则、审计工具组合。</p><p><strong>Lookalike Tools</strong>：攻击者创建恶意 Server 伪装成官方。缓解：使用 MCP Registry 验证身份。</p><h3 id="生产必备配置" tabindex="-1">生产必备配置 <a class="header-anchor" href="#生产必备配置" aria-label="Permalink to &quot;生产必备配置&quot;">​</a></h3><p>域名白名单（防 SSRF）、响应大小限制（防恶意 Server 返回 1GB）、超时控制（防请求卡住）、熔断器（下游故障时停止重试）、敏感信息用环境变量不硬编码。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>Function Calling 让 LLM 学会请求帮助而不是瞎编</li><li>工具定义三部分：元数据、参数（description 最关键）、执行逻辑</li><li>工具数量控制在 3-5 个，按任务类型过滤</li><li>MCP 协议：工具的 USB 接口，2025 年成为事实标准</li><li>安全：Prompt Injection、权限组合攻击、域名白名单、熔断器</li></ul><hr><p><strong>上一章</strong>: <a href="./01-Agent的本质.html">Agent的本质</a> | <strong>下一章</strong>: <a href="./03-记忆与上下文.html">记忆与上下文</a></p>',15))])}const M=A(u,[["render",d]]);export{P as __pageData,M as default};
